1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const FOLLOWUP_DISCOUNT_RATE = 0.15;
28	
29	const sum = (values: number[]): number =>
30	  values.reduce((total, value) => total + value, 0);
31	
32	// Policy-wide discounts, each a rate applied to the policy base premium when its
33	// condition holds. Parallels mainItemSurchargeRates as the single source of
34	// truth for the discount model.
35	const policyWideDiscountRates = (
36	  customer: Customer,
37	  contractIndex: number,
38	): number[] => [
39	  ...(customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
40	    ? [LOYALTY_DISCOUNT_RATE]
41	    : []),
42	  ...(contractIndex >= 1 ? [FOLLOWUP_DISCOUNT_RATE] : []),
43	];
44	
45	// Item-specific surcharges, each a rate applied additively to the base premium
46	// when its condition holds. First insurance always applies; the rest are
47	// conditional on the item.
48	const mainItemSurchargeRates = (item: Item): number[] => [
49	  FIRST_INSURANCE_RATE,
50	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
51	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
52	    ? [HIGH_ENCHANTMENT_RATE]
53	    : []),
54	];
55	
56	// The additive surcharge model: a base premium scaled by 1 plus the sum of all
57	// applicable rates. Shared by every premium path (single source of truth).
58	const applyRates = (basePremium: number, rates: number[]): number =>
59	  basePremium * (1 + sum(rates));
60	
61	// A main item's raw base premium, before any surcharges — the basis for both the
62	// surcharged premium and the policy-wide discount.
63	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type];
64	
65	// A main item's premium: its base premium with all applicable surcharge rates applied.
66	const mainItemPremium = (item: Item): number =>
67	  applyRates(mainItemBase(item), mainItemSurchargeRates(item));
68	
69	const COMPONENT_TYPES = ["rune", "moonstone"];
70	const COMPONENT_BASE_PREMIUM = 25;
71	const COMPONENT_BLOCK_SIZE = 3;
72	const COMPONENT_BLOCK_PREMIUM = 60;
73	
74	const isComponent = (item: Item): boolean =>
75	  COMPONENT_TYPES.includes(item.type);
76	
77	// A type we can price: either a known component or a known main item. Anything
78	// else has no base premium and cannot be quoted.
79	const isKnownItemType = (item: Item): boolean =>
80	  isComponent(item) || item.type in BASE_PREMIUMS;
81	
82	// Base premium for `count` alike components: a block premium applies only for
83	// exactly one block's worth (3) of components; otherwise each is priced individually.
84	const componentBasePremium = (count: number): number => {
85	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
86	  return count * COMPONENT_BASE_PREMIUM;
87	};
88	
89	const countByType = (items: Item[]): Map<string, number> => {
90	  const counts = new Map<string, number>();
91	  for (const item of items) {
92	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
93	  }
94	  return counts;
95	};
96	
97	// The block rule is per-type ("alike" = same type), so price each type's count
98	// independently. componentBasePremium(count) is the raw per-type base; both the
99	// surcharged premium and the policy-wide raw base build on it.
100	const componentTypeBases = (componentItems: Item[]): number[] =>
101	  [...countByType(componentItems).values()].map(componentBasePremium);
102	
103	// Every item is treated as first insurance today, so the surcharge is applied
104	// uniformly to each base premium, using the same additive rate as main items.
105	const withFirstInsurance = (basePremium: number): number =>
106	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
107	
108	const componentItemsPremium = (componentItems: Item[]): number =>
109	  sum(componentTypeBases(componentItems).map(withFirstInsurance));
110	
111	// The policy base premium is the sum of raw item base premiums (no item
112	// surcharges); policy-wide discounts are percentages of this amount.
113	const policyBasePremium = (mainItems: Item[], componentItems: Item[]): number =>
114	  sum(mainItems.map(mainItemBase)) + sum(componentTypeBases(componentItems));
115	
116	// Round up in MHPCO's favour, guarding against floating-point noise
117	// (e.g. 197.50000000001 should still round to 198, not 199).
118	const roundUpInMHPCOFavor = (amount: number): number =>
119	  Math.ceil(Number(amount.toFixed(6)));
120	
121	// Payouts round down in MHPCO's favour — the mirror of roundUpInMHPCOFavor for
122	// premiums. Same floating-point guard so e.g. 350.49999999 still floors to 350.
123	const roundDownInMHPCOFavor = (amount: number): number =>
124	  Math.floor(Number(amount.toFixed(6)));
125	
126	// Every insured item must be a known main item or a known component; an
127	// unrecognised type cannot be priced.
128	const requireKnownItemTypes = (items: Item[]): void => {
129	  for (const item of items) {
130	    if (!isKnownItemType(item)) {
131	      throw new Error(`Unknown item type: ${item.type}`);
132	    }
133	  }
134	};
135	
136	export const quote = (
137	  items: Item[],
138	  customer: Customer,
139	  contractIndex: number,
140	): number => {
141	  requireKnownItemTypes(items);
142	  const mainItems = items.filter((item) => !isComponent(item));
143	  const componentItems = items.filter((item) => isComponent(item));
144	
145	  const mainPremium = sum(mainItems.map(mainItemPremium));
146	  const componentPremium = componentItemsPremium(componentItems);
147	
148	  const policyWideDiscount =
149	    sum(policyWideDiscountRates(customer, contractIndex)) *
150	    policyBasePremium(mainItems, componentItems);
151	
152	  return roundUpInMHPCOFavor(
153	    mainPremium + componentPremium - policyWideDiscount + PROCESSING_FEE,
154	  );
155	};
