157	export interface Damage {
158	  itemType: string;
159	  amount: number;
160	}
161	
162	export interface Incident {
163	  cause: string;
164	  damages: Damage[];
165	}
166	
167	export interface Policy {
168	  items: Item[];
169	}
170	
171	export interface ClaimResult {
172	  payout: number;
173	  remainingCap: number;
174	}
175	
176	// Unmodified insurance value per item; the policy's insurance sum (and hence
177	// its payout cap) is derived from these, never from premium modifiers.
178	const INSURANCE_VALUES: Record<string, number> = {
179	  sword: 1000,
180	  amulet: 600,
181	  staff: 800,
182	  potion: 400,
183	  rune: 250,
184	  moonstone: 250,
185	};
186	
187	export const insuranceSum = (items: Item[]): number =>
188	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
189	
190	const DEDUCTIBLE_PER_EVENT = 100;
191	const ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
192	const ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
193	const FULL_REIMBURSEMENT_RATE = 1;
194	
195	// Highly enchanted items (enchantment >= 8) are reimbursed at a reduced rate,
196	// reflecting their volatility under repair.
197	const isHighlyEnchanted = (item: Item): boolean =>
198	  (item.enchantment ?? 0) >= ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
199	
200	// The insured item a damage refers to, looked up by type from the policy, or a
201	// thrown error if the policy does not cover that item type. Damage to an
202	// uninsured item is never reimbursable, and the returned (non-undefined) item
203	// supplies the attributes the reimbursement rate depends on.
204	const requireInsuredItem = (damage: Damage, policy: Policy): Item => {
205	  const item = policy.items.find((item) => item.type === damage.itemType);
206	  if (!item) {
207	    throw new Error(`Damaged item not covered by policy: ${damage.itemType}`);
208	  }
209	  return item;
210	};
211	
212	// A single damage's reimbursement: the covered amount net of the per-event
213	// deductible. The covered amount is the full damage, except for highly
214	// enchanted items, which are covered at ENCHANTMENT_REIMBURSEMENT_RATE.
215	// Input preconditions (non-negative amounts, covered counts) are checked at
216	// claim entry, so this need only compute.
217	const damageReimbursement = (damage: Damage, policy: Policy): number => {
218	  const item = requireInsuredItem(damage, policy);
219	  const rate = isHighlyEnchanted(item)
220	    ? ENCHANTMENT_REIMBURSEMENT_RATE
221	    : FULL_REIMBURSEMENT_RATE;
222	  const coveredAmount = rate * damage.amount;
223	  return coveredAmount - DEDUCTIBLE_PER_EVENT;
224	};
225	
226	// A damage amount is the value lost, so it can never be negative.
227	const requireNonNegativeDamages = (incident: Incident): void => {
228	  for (const damage of incident.damages) {
229	    if (damage.amount < 0) {
230	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
231	    }
232	  }
233	};
234	
235	// A policy cannot be claimed for more damages of a type than it insures items
236	// of that type (e.g. two sword damages against a single insured sword).
237	const requireDamagesWithinCover = (incident: Incident, policy: Policy): void => {
238	  const insuredCounts = countByType(policy.items);
239	  const damageCounts = countByType(
240	    incident.damages.map((damage) => ({ type: damage.itemType })),
241	  );
242	  for (const [type, damaged] of damageCounts) {
243	    if (damaged > (insuredCounts.get(type) ?? 0)) {
244	      throw new Error(`More damages than insured items for type: ${type}`);
245	    }
246	  }
247	};
248	
249	export const claim = (
250	  policy: Policy,
251	  incident: Incident,
252	  remainingCap: number,
253	): ClaimResult => {
254	  requireNonNegativeDamages(incident);
255	  requireDamagesWithinCover(incident, policy);
256	  const grossPayout = roundDownInMHPCOFavor(
257	    sum(incident.damages.map((damage) => damageReimbursement(damage, policy))),
258	  );
259	  // The policy's remaining cap limits the payout; the desired amount is reduced
260	  // to whatever cap is left.
261	  const payout = Math.min(grossPayout, remainingCap);
262	  return { payout, remainingCap: remainingCap - payout };
263	};
