97	// The block rule is per-type ("alike" = same type), so price each type's count
98	// independently. componentBasePremium(count) is the raw per-type base; both the
99	// surcharged premium and the policy-wide raw base build on it.
100	const componentTypeBases = (componentItems: Item[]): number[] =>
101	  [...countByType(componentItems).values()].map(componentBasePremium);
102	
103	// Every item is treated as first insurance today, so the surcharge is applied
104	// uniformly to each base premium, using the same additive rate as main items.
105	const withFirstInsurance = (basePremium: number): number =>
106	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
107	
108	const componentItemsPremium = (componentItems: Item[]): number =>
109	  sum(componentTypeBases(componentItems).map(withFirstInsurance));
110	
111	// The policy base premium is the sum of raw item base premiums (no item
112	// surcharges); policy-wide discounts are percentages of this amount.
113	const policyBasePremium = (mainItems: Item[], componentItems: Item[]): number =>
114	  sum(mainItems.map(mainItemBase)) + sum(componentTypeBases(componentItems));
115	
116	// Round up in MHPCO's favour, guarding against floating-point noise
117	// (e.g. 197.50000000001 should still round to 198, not 199).
118	const roundUpInMHPCOFavor = (amount: number): number =>
119	  Math.ceil(Number(amount.toFixed(6)));
120	
121	// Payouts round down in MHPCO's favour — the mirror of roundUpInMHPCOFavor for
122	// premiums. Same floating-point guard so e.g. 350.49999999 still floors to 350.
123	const roundDownInMHPCOFavor = (amount: number): number =>
124	  Math.floor(Number(amount.toFixed(6)));
125	
126	// Every insured item must be a known main item or a known component; an
127	// unrecognised type cannot be priced.
128	const requireKnownItemTypes = (items: Item[]): void => {
129	  for (const item of items) {
130	    if (!isKnownItemType(item)) {
131	      throw new Error(`Unknown item type: ${item.type}`);
132	    }
133	  }
134	};
135	
136	export const quote = (
137	  items: Item[],
138	  customer: Customer,
139	  contractIndex: number,
140	): number => {
141	  requireKnownItemTypes(items);
142	  const mainItems = items.filter((item) => !isComponent(item));
143	  const componentItems = items.filter((item) => isComponent(item));
144	
145	  const mainPremium = sum(mainItems.map(mainItemPremium));
146	  const componentPremium = componentItemsPremium(componentItems);
147	
148	  const policyWideDiscount =
149	    sum(policyWideDiscountRates(customer, contractIndex)) *
150	    policyBasePremium(mainItems, componentItems);
151	
152	  return roundUpInMHPCOFavor(
153	    mainPremium + componentPremium - policyWideDiscount + PROCESSING_FEE,
154	  );
155	};
